',{id:"xref_gentrification_displacement_rate",title:"Gentrification rate vs. low-income resident displacement by metro 2010-2024 - does renewal displace the poor?",sub:"San Francisco: 43% of low-income census tracts gentrified 2010-2024, with average 31% displacement of original residents. Portland: 38% gentrified, 22% displaced. The gentrification-displacement correlation (r=0.61) is real but displacement is not automatic - policy choices moderate the relationship strongly.",type:"XREF",geo:"us_metro",fmt:"Scatter plot",tbl:"National Community Reinvestment Coalition gentrification index + ACS tract population change",section:"Housing",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["home_price_pct_change_2005_2024","median_household_income"],join:["pct_on_snap","housing_permits_total","population_pct_change"],sc:{emotional:8,relatability:7,surprise:7,tension:7,visual:5,data_ready:7,originality:7},vs:73,tags:"gentrification displacement rate metro 2010 2024 San Francisco 43% 31% displaced Portland 38% 22% r=0.61 policy moderates NCRC ACS tract population"}',
',{id:"us_racial_segregation_index_by_metro",title:"Residential segregation index by metro 2024 - the most and least segregated cities in America",sub:"Milwaukee WI: dissimilarity index 0.79 - the most racially segregated major metro in the US. Detroit: 0.76. Chicago: 0.74. San Jose: 0.41. The segregation map has barely moved since 1970 in most metros despite 50 years of fair housing law. Legal desegregation and residential desegregation are two different things.",type:"MAP",geo:"us_metro",fmt:"City map",tbl:"Brookings Institution metro segregation index 2024 + ACS racial distribution by tract",section:"Population",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["population_per_sq_km","language_diversity_index"],join:["median_household_income","pct_bachelors","housing_permits_total"],sc:{emotional:8,relatability:6,surprise:7,tension:7,visual:7,data_ready:8,originality:5},vs:73,tags:"racial segregation index metro 2024 Milwaukee 0.79 most Detroit 0.76 Chicago 0.74 San Jose 0.41 barely moved 1970 fair housing legal residential different Brookings ACS"}',
',{id:"xref_urban_rural_mortality_gap_cause",title:"Urban vs. rural mortality gap by cause of death - the diverging health outcomes of geography",sub:"Rural counties: 172 deaths per 100K from heart disease vs. urban 139. But urban: 82 per 100K drug overdose vs. rural 31 (post-2019 reversal). The urban-rural health gap has reversed for some causes and widened for others since 2010. Where you live now predicts how you die more than it did in 2000.",type:"CHART",geo:"us_county",fmt:"Bar chart",tbl:"CDC WONDER cause-specific mortality urban-rural classification 2010-2024 (public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","CDC WONDER: mortality + disease rates by county/state (wonder.cdc.gov - free)"],vars:["rural_population_pct","per_capita_health_spending"],join:["median_household_income","uninsured_rate","pct_on_medicaid"],sc:{emotional:8,relatability:7,surprise:7,tension:6,visual:6,data_ready:9,originality:6},vs:73,tags:"urban rural mortality gap cause death heart disease 172 vs 139 overdose 82 vs 31 reversed widened 2010 geography predicts how you die CDC WONDER classification"}',
',{id:"metro_housing_cost_burden_by_income_tier",title:"Housing cost burden by income tier by metro - who is overpaying for housing",sub:"San Jose: 71% of renters earning under $35K spend more than 30% of income on housing. But even middle-income renters ($50-75K): 44% are cost-burdened. The housing crisis is no longer just a poverty problem - it has climbed into the middle class in every major coastal metro.",type:"MAP",geo:"us_metro",fmt:"City map",tbl:"HUD CHAS housing cost burden data by income tier by metro (public)",section:"Housing",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["home_price_index_2024","median_household_income"],join:["housing_permits_total","pct_under_25k","avg_commute_time"],sc:{emotional:8,relatability:9,surprise:7,tension:7,visual:7,data_ready:9,originality:6},vs:79,tags:"housing cost burden income tier metro San Jose 71% renters under $35K 30% middle $50-75K 44% coastal middle class crisis climbed HUD CHAS"}',
',{id:"xref_city_density_vs_carbon_per_capita",title:"City population density vs. carbon emissions per capita - do dense cities save the planet?",sub:"New York City: 27,000 per sq mile, 6.3 metric tons CO2 per resident. Atlanta: 700 per sq mile, 14.8 tons. Denser cities emit dramatically less carbon per capita - but only because transit and smaller homes reduce energy use. The density-carbon relationship (r=-0.72) is one of the strongest in urban sustainability data.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"Brookings metro carbon inventory + Census population density (both public)",section:"Geography",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)"],vars:["population_per_sq_km","energy_consumption_per_capita"],join:["avg_commute_time","housing_cpi","renewable_energy_share"],sc:{emotional:7,relatability:7,surprise:7,tension:5,visual:5,data_ready:7,originality:6},vs:65,tags:"city density carbon per capita New York 27000 6.3 tons Atlanta 700 14.8 tons transit smaller homes r=-0.72 strongest urban sustainability Brookings Census"}',
',{id:"xref_city_minimum_wage_vs_fast_food_employment",title:"City minimum wage vs. fast food employment growth - the Seattle experiment results",sub:"Seattle raised minimum wage to $15 in 2015. 5 years later: fast food employment grew 9.4%. Comparable non-Seattle metros: 8.9% growth. The feared fast food job losses did not materialize. The Seattle experiment is the most-studied natural minimum wage experiment in US economic history.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"University of Washington Seattle minimum wage study + BLS QCEW fast food employment (public)",section:"Labor Force",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["manufacturing_hourly_wages_state","state_unemployment_rate"],join:["median_household_income","pct_under_25k","housing_cpi"],sc:{emotional:7,relatability:8,surprise:8,tension:5,visual:4,data_ready:8,originality:7},vs:70,tags:"city minimum wage fast food employment Seattle $15 2015 5 years 9.4% vs 8.8% no losses most-studied natural experiment UW BLS QCEW"}',
',{id:"urban_heat_island_intensity_by_city",title:"Urban heat island intensity by city - how much hotter cities are than their surrounding countryside",sub:"Phoenix AZ: 10.1 degrees Celsius hotter in urban core vs. surrounding desert. Las Vegas: 8.7 degrees. Atlanta: 5.2. New York: 3.8. The urban heat island map reveals both the thermal penalty of density and the crucial role of tree canopy and reflective surfaces in moderating it.",type:"MAP",geo:"us_city",fmt:"City map",tbl:"NOAA urban heat island analysis + satellite surface temperature data (public)",section:"Geography",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)"],vars:["population_per_sq_km","mean_elevation"],join:["energy_consumption_per_capita","housing_cpi","pct_forest"],sc:{emotional:6,relatability:7,surprise:7,tension:5,visual:9,data_ready:7,originality:6},vs:66,tags:"urban heat island intensity city Phoenix 10.1C Las Vegas 8.7 Atlanta 5.2 New York 3.8 thermal penalty tree canopy reflective NOAA satellite surface temperature"}',
',{id:"xref_transit_investment_vs_property_value",title:"Transit investment vs. property value increase by corridor - does the subway make you rich?",sub:"Washington DC Metro Silver Line corridor 2014-2024: properties within 0.5 miles of new stations appreciated 34% more than comparable properties 1 mile away. The transit-property value premium averages 18% nationally for rail transit. The subsidy argument: transit is paid for publicly but the value is captured privately.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"WMATA economic impact data + Zillow corridor analysis (public academic)",section:"Transportation",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["avg_commute_time","home_price_index_2024"],join:["median_household_income","population_pct_change","housing_permits_total"],sc:{emotional:7,relatability:7,surprise:7,tension:5,visual:5,data_ready:7,originality:7},vs:65,tags:"transit investment property value corridor DC Metro Silver Line 0.5 miles 34% more 18% national premium paid public value private WMATA Zillow corridor"}',
',{id:"xref_neighborhood_income_vs_school_quality",title:"Neighborhood income vs. elementary school test score by metro - the school quality zip code lottery",sub:"In Chicago: census tracts in the top income quartile have elementary schools averaging 68th national percentile scores. Bottom quartile: 28th percentile. The income-school quality correlation within metros (r=0.74) is tighter than between states. Your school quality is your neighbor\'s income.",type:"XREF",geo:"us_metro",fmt:"Scatter plot",tbl:"Stanford Education Opportunity Project school scores + ACS tract income (both public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["expenditure_per_pupil","median_household_income"],join:["pct_bachelors","pct_on_snap","housing_cpi"],sc:{emotional:9,relatability:8,surprise:7,tension:7,visual:5,data_ready:8,originality:5},vs:78,tags:"neighborhood income school quality metro Chicago top quartile 68th percentile bottom 28th r=0.74 within metro zip code lottery Stanford Education Opportunity ACS tract"}',
',{id:"xref_street_design_vs_pedestrian_fatalities",title:"Street design type vs. pedestrian fatality rate by city - arterials are killing machines",sub:"Cities with high proportions of wide arterial roads (5+ lanes, 45mph) have pedestrian fatality rates 3.8x higher than cities with grid-street design of narrow lanes. The pedestrian safety crisis is primarily an infrastructure problem, not a behavior problem. Engineering choices determine who dies.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"NHTSA pedestrian fatality data + FHWA road design classification by city (both public)",section:"Transportation",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["avg_commute_time","population_per_sq_km"],join:["median_household_income","rural_population_pct","housing_cpi"],sc:{emotional:8,relatability:7,surprise:8,tension:7,visual:5,data_ready:7,originality:8},vs:74,tags:"street design pedestrian fatality city arterial wide 5+ lanes 3.8x higher grid narrow lane infrastructure not behavior engineering determines NHTSA FHWA road design"}',
',{id:"county_short_term_rental_share_map",title:"Airbnb and short-term rental share of housing stock by county - the vacation rental footprint",sub:"Nye County NV (Las Vegas exurbs): 18.4% of housing units listed as short-term rentals. Dare County NC (Outer Banks): 16.2%. The STR concentration geography reveals where vacation rental platforms have most displaced long-term housing supply - and these counties overwhelmingly have the highest rent growth.",type:"MAP",geo:"us_county",fmt:"County choropleth",tbl:"AirDNA short-term rental data + ACS housing units by county (public with subscription for AirDNA)",section:"Housing",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["home_price_pct_change_2005_2024","housing_permits_total"],join:["median_household_income","population_pct_change","rural_population_pct"],sc:{emotional:7,relatability:7,surprise:7,tension:6,visual:8,data_ready:6,originality:7},vs:67,tags:"Airbnb short-term rental housing stock county Nye NV 18.4% Dare NC 16.2% Outer Banks vacation displaced long-term supply highest rent growth AirDNA ACS housing units"}',
',{id:"xref_city_size_vs_productivity_premium",title:"City population vs. GDP per worker - the agglomeration productivity bonus",sub:"Doubling city size is associated with a 6-8% increase in GDP per worker - the agglomeration economy premium. New York: $124K GDP per worker vs. the US average of $89K. The relationship is a power law. The largest cities are not just concentrations of workers - they make those workers systematically more productive.",type:"XREF",geo:"us_metro",fmt:"Scatter plot",tbl:"BEA metro GDP + BLS metro employment (both public)",section:"Income",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["state_gdp_per_capita","population_per_sq_km"],join:["median_household_income","pct_bachelors","housing_cpi"],sc:{emotional:5,relatability:6,surprise:7,tension:3,visual:6,data_ready:9,originality:5},vs:58,tags:"city size GDP per worker agglomeration productivity doubling 6-8% New York $124K US $89K power law not just concentration systematically more productive BEA BLS metro"}',
',{id:"xref_homicide_rate_vs_gun_access_city",title:"Homicide rate vs. gun access rate by city - the firearm availability geography of violence",sub:"New Orleans LA: 51 homicides per 100K (2023), estimated 73% of households with firearms. Hartford CT: 28 per 100K, 17% household firearm ownership. The correlation between firearm availability and homicide (r=0.68) is real but endogeneity makes causal direction contested - high-crime areas may acquire more guns in response.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"FBI UCR city homicide data + RAND gun ownership estimates by state/metro (public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","FBI Crime Data Explorer: UCR/NIBRS by state/agency (cde.ucr.cjis.gov - free)"],vars:["murder_rate","violent_crime_rate"],join:["median_household_income","pct_on_snap","rural_population_pct"],sc:{emotional:8,relatability:6,surprise:7,tension:8,visual:4,data_ready:7,originality:6},vs:72,tags:"homicide rate gun access city New Orleans 51 73% Hartford 28 17% r=0.68 endogeneity causal contested high-crime acquire response FBI UCR RAND gun ownership estimates"}',
',{id:"xref_public_housing_density_vs_concentrated_poverty",title:"Public housing project density vs. concentrated poverty rate by metro - did public housing create poverty?",sub:"Metros that built high-density public housing projects in the 1960s-70s have 40% higher rates of concentrated poverty (poverty rate 40%+) in those same census tracts today vs. metros that distributed public housing. The architecture of poverty concentration was a policy choice.",type:"XREF",geo:"us_metro",fmt:"Scatter plot",tbl:"HUD Picture of Subsidized Households + ACS tract poverty concentration (both public)",section:"Housing",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["median_household_income","pct_on_snap"],join:["housing_permits_total","rural_population_pct","pct_bachelors"],sc:{emotional:8,relatability:5,surprise:8,tension:7,visual:4,data_ready:7,originality:8},vs:71,tags:"public housing density concentrated poverty metro 1960s-70s high-density projects 40% higher 40%+ poverty tracts today distributed architecture policy choice HUD ACS tract"}',
',{id:"xref_noise_pollution_vs_income_city",title:"Noise pollution levels vs. median income by census tract - silence is a luxury good",sub:"New York City: census tracts in bottom income quartile experience average 72 dB ambient noise. Top income quartile: 64 dB. An 8 dB difference corresponds to roughly 2.5x perceived loudness. The noise-income gradient exists in every major US city - quieter neighborhoods cost more because quiet costs money.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"USDOT Bureau of Transportation Statistics noise model + ACS tract income (both public)",section:"Geography",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["population_per_sq_km","median_household_income"],join:["home_price_index_2024","avg_commute_time","pct_bachelors"],sc:{emotional:7,relatability:7,surprise:7,tension:4,visual:5,data_ready:7,originality:8},vs:65,tags:"noise pollution income city New York bottom quartile 72 dB top 64 dB 8 dB 2.5x louder gradient every major city quiet costs money USDOT BTS noise model ACS tract"}',
',{id:"xref_city_parking_minimum_vs_housing_density",title:"Parking minimum requirements vs. housing density by city - how parking law shapes the built environment",sub:"Houston eliminated parking minimums in 2019 in inner loop neighborhoods. Housing permits in those areas grew 34% faster than comparable areas with minimums 2019-2023. Parking minimums force land to be used for cars instead of people, directly reducing housing supply.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"SPUR/Parking Reform Network municipal parking requirement database + Census housing permits",section:"Transportation",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["housing_permits_total","population_per_sq_km"],join:["home_price_index_2024","median_household_income","avg_commute_time"],sc:{emotional:6,relatability:7,surprise:8,tension:4,visual:5,data_ready:6,originality:8},vs:64,tags:"parking minimum housing density city Houston eliminated 2019 34% faster permits 2019-2023 land for cars not people supply reduced SPUR Parking Reform Network Census"}',
',{id:"xref_walkability_score_vs_property_value",title:"Walk Score vs. home price by metro area - the dollar value of walkability",sub:"Across US metros: a 10-point increase in Walk Score is associated with a $5,400 to $17,800 increase in median home price (range reflects metro variation). In San Francisco: each Walk Score point adds $3,200. The walkability premium is highest where car dependency is most replaceable by transit.",type:"XREF",geo:"us_metro",fmt:"Scatter plot",tbl:"Walk Score API data + Zillow metro median home price 2024 (Walk Score public, Zillow public)",section:"Transportation",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","HUD Fair Market Rents + housing data by state/county (huduser.gov - free)"],vars:["avg_commute_time","population_per_sq_km"],join:["home_price_index_2024","median_household_income","housing_permits_total"],sc:{emotional:6,relatability:8,surprise:7,tension:3,visual:5,data_ready:7,originality:5},vs:60,tags:"walkability Walk Score home price metro 10 points $5400-$17800 San Francisco $3200 per point transit replaceable Walk Score API Zillow median 2024 dollar value"}',
',{id:"xref_neighborhood_change_vs_police_stops",title:"Neighborhood racial composition change vs. police stop rate by city - policing and neighborhood transition",sub:"In Chicago: census tracts that were majority Black but transitioned toward majority white or mixed 2010-2020 showed police stop rates fall 34% after the transition. Controlling for crime rates, race of neighborhood predicts police activity independently. The geography of policing follows demographic geography.",type:"XREF",geo:"us_city",fmt:"Scatter plot",tbl:"Stanford Open Policing Project city stop data + ACS tract racial composition change (public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","Census Population Estimates: annual population by state/county (census.gov - free)","FBI Crime Data Explorer: UCR/NIBRS by state/agency (cde.ucr.cjis.gov - free)"],vars:["violent_crime_rate","population_per_sq_km"],join:["median_household_income","pct_bachelors","rural_population_pct"],sc:{emotional:9,relatability:5,surprise:8,tension:8,visual:4,data_ready:7,originality:8},vs:78,tags:"neighborhood racial composition police stops city Chicago majority Black transitioned mixed white 34% fall crime controlled race predicts independently Stanford Open Policing ACS tract"}',
',{id:"metro_foreign_born_health_advantage",title:"Foreign-born vs. native-born mortality rate by metro - the immigrant health paradox",sub:"First-generation immigrants in the US have mortality rates 24% lower than native-born Americans of the same income and education. The advantage erodes by the second generation and disappears by the third. Assimilation into American health behavior patterns explains the convergence - the paradox is that becoming American makes you less healthy.",type:"CHART",geo:"us_metro",fmt:"Bar chart",tbl:"CDC WONDER mortality by nativity + ACS nativity data (both public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","CDC WONDER: mortality + disease rates by county/state (wonder.cdc.gov - free)"],vars:["net_migration_rate","per_capita_health_spending"],join:["median_household_income","pct_bachelors","uninsured_rate"],sc:{emotional:8,relatability:6,surprise:9,tension:6,visual:5,data_ready:7,originality:8},vs:74,tags:"foreign-born native-born mortality metro immigrant health paradox 24% lower first generation erodes second disappears third American behavior assimilation CDC WONDER ACS nativity"}'
